import { useState } from "react";

export default function NestedList() {
  const [root, setRoot] = useState({
    title: "Главный список",
    collapsed: false,
    children: [] // каждый child = { id, title, fields: [{id, value}] }
  });

  // --- ROOT FUNCTIONS ---
  const toggleRoot = () => {
    setRoot(prev => ({ ...prev, collapsed: !prev.collapsed }));
  };

  const addChild = () => {
    setRoot(prev => ({
      ...prev,
      children: [
        ...prev.children,
        {
          id: crypto.randomUUID(),
          title: "",
          fields: [],
          collapsed: false
        }
      ]
    }));
  };

  // --- CHILD FUNCTIONS ---
  const toggleChild = (id) => {
    setRoot(prev => ({
      ...prev,
      children: prev.children.map(c =>
        c.id === id ? { ...c, collapsed: !c.collapsed } : c
      )
    }));
  };

  const updateChildTitle = (id, value) => {
    setRoot(prev => ({
      ...prev,
      children: prev.children.map(c =>
        c.id === id ? { ...c, title: value } : c
      )
    }));
  };

  const addField = (childId) => {
    setRoot(prev => ({
      ...prev,
      children: prev.children.map(c =>
        c.id === childId
          ? {
              ...c,
              fields: [...c.fields, { id: crypto.randomUUID(), value: "" }]
            }
          : c
      )
    }));
  };

  const updateField = (childId, fieldId, value) => {
    setRoot(prev => ({
      ...prev,
      children: prev.children.map(c =>
        c.id === childId
          ? {
              ...c,
              fields: c.fields.map(f =>
                f.id === fieldId ? { ...f, value } : f
              )
            }
          : c
      )
    }));
  };

  const deleteField = (childId, fieldId) => {
    setRoot(prev => ({
      ...prev,
      children: prev.children.map(c =>
        c.id === childId
          ? { ...c, fields: c.fields.filter(f => f.id !== fieldId) }
          : c
      )
    }));
  };

  // ---------- RENDER ----------
  return (
    <div style={{ border: "1px solid #aaa", padding: 10, margin: 10 }}>
      {/* ROOT HEADER */}
      <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
        <svg
          onClick={toggleRoot}
          style={{
            width: 20,
            height: 20,
            cursor: "pointer",
            transform: root.collapsed ? "rotate(0deg)" : "rotate(180deg)",
            transition: "0.2s"
          }}
        >
          <use href="#icon-expand" />
        </svg>
        <h2 style={{ margin: 0, flex: 1 }}>{root.title}</h2>

        <svg
          onClick={addChild}
          style={{ width: 20, height: 20, cursor: "pointer" }}
        >
          <use href="#icon-plus" />
        </svg>
      </div>

      {/* ROOT CONTENT */}
      {!root.collapsed && (
        <div style={{ marginLeft: 25, marginTop: 10 }}>
          {root.children.map((child) => (
            <div
              key={child.id}
              style={{
                border: "1px solid #ccc",
                padding: 8,
                marginBottom: 8,
                borderRadius: 6,
                background: "#fafafa"
              }}
            >
              {/* CHILD HEADER */}
              <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                <svg
                  onClick={() => toggleChild(child.id)}
                  style={{
                    width: 18,
                    height: 18,
                    cursor: "pointer",
                    transform: child.collapsed ? "rotate(0deg)" : "rotate(180deg)",
                    transition: "0.2s"
                  }}
                >
                  <use href="#icon-expand" />
                </svg>

                <input
                  placeholder="Название списка"
                  value={child.title}
                  onChange={(e) => updateChildTitle(child.id, e.target.value)}
                  style={{ flex: 1, padding: 4 }}
                />

                <svg
                  onClick={() => addField(child.id)}
                  style={{ width: 18, height: 18, cursor: "pointer" }}
                >
                  <use href="#icon-plus" />
                </svg>
              </div>

              {/* CHILD CONTENT */}
              {!child.collapsed && (
                <div style={{ marginLeft: 20, marginTop: 6 }}>
                  {child.fields.map((f) => (
                    <div
                      key={f.id}
                      style={{
                        display: "flex",
                        alignItems: "center",
                        gap: 6,
                        marginBottom: 4
                      }}
                    >
                      <input
                        value={f.value}
                        onChange={(e) =>
                          updateField(child.id, f.id, e.target.value)
                        }
                        style={{ flex: 1, padding: 4 }}
                      />
                      <span
                        onClick={() => deleteField(child.id, f.id)}
                        style={{ color: "red", cursor: "pointer" }}
                      >
                        Удалить
                      </span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
